import { useEffect, useState } from 'react';
import api from '../../api/client';
import AppNavbar from '../../components/AppNavbar';

export default function DeveloperDashboard() {
  const [tickets, setTickets] = useState([]);
  const [error, setError] = useState('');

  const loadTickets = async () => {
    try {
      const res = await api.get('/tickets/');
      setTickets(res.data);
    } catch (err) {
      console.error(err);
      setError('Failed to load developer tickets');
    }
  };

  useEffect(() => {
    loadTickets();
  }, []);

  const handleUpdate = async (ticketId, status, developer_remark) => {
    try {
      await api.post(`/tickets/${ticketId}/developer_update/`, {
        status,
        developer_remark,
      });
      loadTickets();
    } catch (err) {
      console.error(err);
      alert('Failed to update ticket');
    }
  };

  return (
    <>
      <AppNavbar />
      <div className="container mt-4">
        <h2 className="mb-4">Developer Dashboard</h2>

        {error && <div className="alert alert-danger">{error}</div>}

        <div className="card">
          <div className="card-body">
            <h4 className="mb-3">Tickets Sent to Development</h4>

            <div className="table-responsive">
              <table className="table table-bordered table-striped">
                <thead>
                  <tr>
                    <th>Ticket ID</th>
                    <th>Department</th>
                    <th>Divis</th>
                    <th>Module</th>
                    <th>Submodule</th>
                    <th>Subject</th>
                    <th>Status</th>
                    <th>Support Remark</th>
                    <th>Developer Remark</th>
                    <th>Update</th>
                  </tr>
                </thead>
                <tbody>
                  {tickets.length ? tickets.map((ticket) => (
                    <tr key={ticket.id}>
                      <td>{ticket.ticket_id}</td>
                      <td>{ticket.department_name || ''}</td>
                      <td>{ticket.module_name || ''}</td>
                      <td>{ticket.submodule_name || ''}</td>
                      <td>{ticket.subject}</td>
                      <td>{ticket.status}</td>
                      <td>{ticket.support_remark || ''}</td>
                      <td>
                        <textarea
                          className="form-control"
                          rows="2"
                          defaultValue={ticket.developer_remark || ''}
                          id={`remark-${ticket.id}`}
                        />
                      </td>
                      <td>
                        <select
                          className="form-select mb-2"
                          defaultValue={ticket.status}
                          id={`status-${ticket.id}`}
                        >
                          <option value="Sent to Developer">Sent to Developer</option>
                          <option value="Developer In Progress">Developer In Progress</option>
                          <option value="Closed">Closed</option>
                          <option value="Reopened">Reopened</option>
                        </select>

                        <button
                          className="btn btn-primary btn-sm"
                          onClick={() =>
                            handleUpdate(
                              ticket.id,
                              document.getElementById(`status-${ticket.id}`).value,
                              document.getElementById(`remark-${ticket.id}`).value
                            )
                          }
                        >
                          Update
                        </button>
                      </td>
                    </tr>
                  )) : (
                    <tr>
                      <td colSpan="9">No development tickets available</td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
